SELECT t2.change_after shortAfter, t2.agent_account agentAccount, t2.operator, t2.operator_time operatorTime from agent_info_change_record t2
t2.change_after is not null and t2.change_after <> ''
AND t2.agent_account = #{vo.agentAccount}
AND t2.change_after like concat('%', #{vo.shortUrl}, '%')
AND t2.operator = #{vo.operator}
order by t2.operator_time asc
